import React, { useEffect, useState } from 'react';
import './CoursesUsPage.css';

const sampleCourses = [
  {
    id: 'c1',
    title: 'Введение в React',
    author: 'Иван Иванов',
    progress: 45,
    lessons: 12,
    thumbnail: '/Files/sample-course-1.jpg',
  },
  {
    id: 'c2',
    title: 'Основы JavaScript',
    author: 'Мария Петрова',
    progress: 80,
    lessons: 18,
    thumbnail: '/Files/sample-course-2.jpg',
  },
];

export default function CoursesUsPage({ courses }) {
  const [userCourses, setUserCourses] = useState(() => courses || []);

  useEffect(() => {
    if (!courses) {
      try {
        const stored = localStorage.getItem('userCourses');
        if (stored) {
          setUserCourses(JSON.parse(stored));
        } else {
          setUserCourses(sampleCourses);
        }
      } catch (e) {
        setUserCourses(sampleCourses);
      }
    }
  }, [courses]);

  if (!userCourses || userCourses.length === 0) {
    return (
      <div className="courses-page empty">
        <h2 className="page-title">Мои курсы</h2>
        <p className="empty-text">У вас пока нет курсов. Посмотрите каталог и добавьте первый курс.</p>
      </div>
    );
  }

  return (
    <div className="courses-page">
      <h2 className="page-title">Мои курсы</h2>
      <ul className="courses-list">
        {userCourses.map((c) => (
          <li key={c.id} className="course-card">
            <div className="thumb-wrap">
              {c.thumbnail ? (
                // image may be relative to public/Files
                // in dev server `/Files/...` is a safe fallback
                <img src={c.thumbnail} alt={c.title} className="course-thumb" />
              ) : (
                <div className="thumb-placeholder">Курс</div>
              )}
            </div>
            <div className="course-info">
              <h3 className="course-title">{c.title}</h3>
              <div className="course-meta">
                <span className="course-author">{c.author}</span>
                <span className="course-lessons">{c.lessons} уроков</span>
              </div>
              <div className="progress-row">
                <div className="progress-bar">
                  <div className="progress-fill" style={{ width: `${c.progress || 0}%` }} />
                </div>
                <span className="progress-num">{c.progress || 0}%</span>
              </div>
              <div className="course-actions">
                <button className="btn primary">Продолжить</button>
                <button className="btn ghost">Редактировать</button>
              </div>
            </div>
          </li>
        ))}
      </ul>
    </div>
  );
}
